$c = Get-Content -Raw "script.js"; $c = [regex]::Replace($c, "border-radius:\s*(4px|6px|8px|10px|12px|16px);?", "border-radius: var(--radius-sm);"); $c = [regex]::Replace($c, "border-radius:\s*(20px|24px|28px);?", "border-radius: var(--radius);"); $c = [regex]::Replace($c, "border-radius:\s*(50px|9999px);?", "border-radius: var(--radius-pill);"); Set-Content -Path "script.js" -Value $c
